 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  ListPageFilter,
 6	  useListPageFilter,
 7	  VirtualizedTable,
 8	} from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  EmptyState,
11	  EmptyStateBody,
12	  EmptyStateHeader,
13	  EmptyStateIcon,
14	  EmptyStateVariant,
15	} from '@patternfly/react-core';
16	import { SearchIcon } from '@patternfly/react-icons';
17	
18	import useSnapshotColumns from '../../hooks/useSnapshotColumns';
19	import { UseSnapshotData } from '../../hooks/useSnapshotData';
20	import { filters } from '../../utils/filters';
21	
22	import SnapshotRow from './SnapshotRow';
23	
24	type SnapshotsListProps = UseSnapshotData & { isVMRunning?: boolean };
25	
26	const SnapshotsList: FC<SnapshotsListProps> = ({
27	  error,
28	  isVMRunning,
29	  loaded,
30	  restoresMap,
31	  snapshots,
32	}) => {
33	  const columns = useSnapshotColumns();
34	  const { t } = useKubevirtTranslation();
35	  const [data, filteredData, onFilterChange] = useListPageFilter(snapshots, filters);
36	
37	  return (
38	    <>
39	      <ListPageFilter
40	        data={data}
41	        loaded={loaded}
42	        onFilterChange={onFilterChange}
43	        rowFilters={filters}
44	      />
45	      <VirtualizedTable
46	        NoDataEmptyMsg={() => (
47	          <>
48	            <EmptyState variant={EmptyStateVariant.xs}>
49	              <EmptyStateHeader
50	                icon={
51	                  <EmptyStateIcon className="snapshots-list__empty-state-icon" icon={SearchIcon} />
52	                }
53	              />
54	              <EmptyStateBody>{t('No snapshots found')}</EmptyStateBody>
55	            </EmptyState>
56	          </>
57	        )}
58	        columns={columns}
59	        data={filteredData}
60	        loaded={loaded}
61	        loadError={error}
62	        Row={SnapshotRow}
63	        rowData={{ isVMRunning, restores: restoresMap }}
64	        unfilteredData={data}
65	      />
66	    </>
67	  );
68	};
69	
70	export default SnapshotsList;

